import torch
import torch.nn as nn
import math
from torch.utils.cpp_extension import load_inline

# Define the fused CUDA kernel with optimized memory access and tiling
fused_activation_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <math.h>

constexpr int TILE_SIZE = 32;
constexpr int BLOCK_SIZE = 256;

template<typename T>
__device__ __forceinline__ T swish_fast(T x) {
    // Fast approximate swish: x * sigmoid(x) ≈ x / (1 + exp(-x))
    T one = 1.0f;
    return x / (one + expf(-x));
}

template<typename T>
__device__ __forceinline__ T clamp_tanh_clamp_fast(T x) {
    // Fused clamp + tanh + clamp with fast approximations
    x = fminf(1.0f, fmaxf(-1.0f, x));
    x = tanhf(x);
    return fminf(1.0f, fmaxf(-1.0f, x));
}

template<typename T>
__global__ void fused_gemm_activation_kernel(
    const T* __restrict__ input,
    const T* __restrict__ weight,
    const T* __restrict__ bias,
    T* __restrict__ output,
    int M, int N, int K) {

    // Shared memory for tiling
    __shared__ T tile_a[TILE_SIZE][TILE_SIZE];
    __shared__ T tile_b[TILE_SIZE][TILE_SIZE];

    const int row = blockIdx.y * TILE_SIZE + threadIdx.y;
    const int col = blockIdx.x * TILE_SIZE + threadIdx.x;

    T thread_sum = 0.0f;

    // Number of tiles needed to cover K dimension
    const int num_tiles = (K + TILE_SIZE - 1) / TILE_SIZE;

    for (int t = 0; t < num_tiles; ++t) {
        // Load input tile
        int input_row = row;
        int input_col = t * TILE_SIZE + threadIdx.x;
        if (input_row < M && input_col < K) {
            tile_a[threadIdx.y][threadIdx.x] = input[input_row * K + input_col];
        } else {
            tile_a[threadIdx.y][threadIdx.x] = 0.0f;
        }

        // Load weight tile (transposed access)
        int weight_row = t * TILE_SIZE + threadIdx.y;
        int weight_col = col;
        if (weight_row < K && weight_col < N) {
            tile_b[threadIdx.y][threadIdx.x] = weight[weight_row * N + weight_col];
        } else {
            tile_b[threadIdx.y][threadIdx.x] = 0.0f;
        }

        __syncthreads();

        // Compute partial sum for this tile
        #pragma unroll
        for (int k = 0; k < TILE_SIZE; ++k) {
            thread_sum += tile_a[threadIdx.y][k] * tile_b[k][threadIdx.x];
        }

        __syncthreads();
    }

    // Write result with fused activation
    if (row < M && col < N) {
        T result = thread_sum;
        if (bias) {
            result += bias[col];
        }

        // Fused activation pipeline
        result = swish_fast(result);
        result = result * 0.5f;  // Faster than division by 2.0
        result = clamp_tanh_clamp_fast(result);

        output[row * N + col] = result;
    }
}

// Optimized kernel for smaller matrices
template<typename T>
__global__ void fused_gemm_activation_small_kernel(
    const T* __restrict__ input,
    const T* __restrict__ weight,
    const T* __restrict__ bias,
    T* __restrict__ output,
    int M, int N, int K) {

    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    const int row = idx / N;
    const int col = idx % N;

    if (row < M && col < N) {
        T sum = bias ? bias[col] : 0.0f;

        // Coalesced memory access
        #pragma unroll(8)
        for (int k = 0; k < K; ++k) {
            sum += input[row * K + k] * weight[k * N + col];
        }

        // Fused activation with fast approximations
        sum = sum / (1.0f + expf(-sum));  // swish
        sum *= 0.5f;  // divide by 2
        sum = fminf(1.0f, fmaxf(-1.0f, sum));  // clamp
        sum = tanhf(sum);  // tanh
        sum = fminf(1.0f, fmaxf(-1.0f, sum));  // clamp

        output[row * N + col] = sum;
    }
}

torch::Tensor fused_gemm_activation_cuda(
    torch::Tensor input, torch::Tensor weight, torch::Tensor bias) {

    auto M = input.size(0);
    auto K = input.size(1);
    auto N = weight.size(1);

    auto output = torch::empty({M, N}, input.options());

    // Choose kernel based on matrix size
    if (M * N <= 4096) {  // Small matrix optimization
        const int threads = 256;
        const int blocks = (M * N + threads - 1) / threads;

        AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "fused_gemm_activation_small", ([&] {
            fused_gemm_activation_small_kernel<scalar_t><<<blocks, threads>>>(
                input.data_ptr<scalar_t>(),
                weight.data_ptr<scalar_t>(),
                bias.defined() ? bias.data_ptr<scalar_t>() : nullptr,
                output.data_ptr<scalar_t>(),
                M, N, K);
        }));
    } else {  // Tiled kernel for larger matrices
        const dim3 block_size(TILE_SIZE, TILE_SIZE);
        const dim3 grid_size(
            (N + TILE_SIZE - 1) / TILE_SIZE,
            (M + TILE_SIZE - 1) / TILE_SIZE);

        AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "fused_gemm_activation", ([&] {
            fused_gemm_activation_kernel<scalar_t><<<grid_size, block_size>>>(
                input.data_ptr<scalar_t>(),
                weight.data_ptr<scalar_t>(),
                bias.defined() ? bias.data_ptr<scalar_t>() : nullptr,
                output.data_ptr<scalar_t>(),
                M, N, K);
        }));
    }

    return output;
}
"""

fused_activation_cpp_source = """
torch::Tensor fused_gemm_activation_cuda(
    torch::Tensor input, torch::Tensor weight, torch::Tensor bias);
"""

# Compile the inline CUDA code with optimization flags
fused_activation = load_inline(
    name="fused_activation",
    cpp_sources=fused_activation_cpp_source,
    cuda_sources=fused_activation_source,
    functions=["fused_gemm_activation_cuda"],
    verbose=False,
    extra_cflags=["-O3", "-march=native"],
    extra_ldflags=["-lcudart"],
    extra_cuda_cflags=["-O3", "--use_fast_math"],
)

class ModelNew(nn.Module):
    """
    Optimized model with fused CUDA kernel using tiled GEMM and fused activations.
    """
    def __init__(self, in_features, out_features, bias=True):
        super(ModelNew, self).__init__()
        self.in_features = in_features
        self.out_features = out_features
        self.bias = bias

        # Initialize weights (already transposed for kernel access)
        self.weight = nn.Parameter(torch.empty(out_features, in_features))
        if bias:
            self.bias_param = nn.Parameter(torch.empty(out_features))
        else:
            self.register_parameter('bias_param', None)

        # Initialize parameters
        self.reset_parameters()

        # Store the fused operation
        self.fused_gemm_activation = fused_activation

    def reset_parameters(self):
        # Kaiming initialization optimized for ReLU-like activations
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        if self.bias_param is not None:
            fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
            bound = 1 / math.sqrt(fan_in) if fan_in > 0 else 0
            nn.init.uniform_(self.bias_param, -bound, bound)

    def forward(self, x):
        """
        Args:
            x (torch.Tensor): Input tensor of shape (batch_size, in_features).
        Returns:
            torch.Tensor: Output tensor of shape (batch_size, out_features).
        """
        # Ensure contiguous memory layout
        x = x.contiguous()
        weight_t = self.weight.t().contiguous()

        # Use fused CUDA kernel
        return self.fused_gemm_activation.fused_gemm_activation_cuda(
            x, weight_t, self.bias_param)

